package com.pufferfishscheduler.common.enums;

import com.pufferfishscheduler.common.exception.BusinessException;
import lombok.Getter;

import java.util.Arrays;
import java.util.Optional;

/**
 * 转换组件类型
 * 1.输入 2.输出 3.清洗 4.流程 5.脚本 6.文件传输 7.其它
 *
 * @author Mayc
 * @since 2026-03-02  23:02
 */
@Getter
public enum TransComponentType {
    INPUT("1", "输入", "data:image/png;base64,"),
    OUTPUT("2", "输出", "data:image/png;base64,"),
    CLEAN("3", "清洗", "data:image/png;base64,"),
    SWITCH("4", "流程", "data:image/png;base64,"),
    SCRIPT("5", "脚本", "data:image/png;base64,"),
    FILE_TRANSFER("6", "文件传输", "data:image/png;base64,"),
    OTHER("7", "其它", "data:image/png;base64,");

    /**
     * 编码
     */
    private final String type;

    /**
     * 描述
     */
    private final String description;

    /**
     * 图标
     */
    private final String icon;

    /**
     * 私有构造函数
     *
     * @param type        组件类型
     * @param description 组件描述
     */
    TransComponentType(String type, String description, String icon) {
        this.type = type;
        this.description = description;
        this.icon = icon;
    }

    /**
     * 根据组件类型获取枚举实例
     *
     * @param type 组件类型
     * @return 匹配的枚举实例，或空 Optional
     */
    public static Optional<TransComponentType> fromCode(String type) {
        return Arrays.stream(TransComponentType.values())
                .filter(status -> status.getType().equals(type))
                .findFirst();
    }

    /**
     *
     * @param code
     * @return
     */
    public static TransComponentType valueOfCode(String code) {
        return fromCode(code)
                .orElseThrow(() -> new BusinessException("无效的组件类型: " + code));
    }
}
